    21→
    22→// === SETTINGS STORE ===
    23→
    24→interface AppearanceSettings {
    25→  theme: 'light' | 'dark' | 'system';
    26→  accentColor: string;
    27→  language: 'it' | 'en' | 'es' | 'fr' | 'de';
    28→}
    29→
    30→// Teaching style from super encouraging to brutal
    31→export type TeachingStyle = 'super_encouraging' | 'encouraging' | 'balanced' | 'strict' | 'brutal';
    32→
    33→/**
    34→ * Learning differences that the platform supports.
    35→ * Used for buddy matching and accessibility features.
