   235→        }
   236→      },
   237→
   238→      loadFromServer: async () => {
   239→        try {
   240→          const [settingsRes, profileRes] = await Promise.all([
   241→            fetch('/api/user/settings'),
   242→            fetch('/api/user/profile'),
   243→          ]);
   244→
   245→          if (settingsRes.ok) {
   246→            const settings = await settingsRes.json();
   247→            set((state) => ({
   248→              theme: settings.theme ?? state.theme,
