   250→              model: settings.model ?? state.model,
   251→              budgetLimit: settings.budgetLimit ?? state.budgetLimit,
   252→              totalSpent: settings.totalSpent ?? state.totalSpent,  // #88: Load from server
   253→              appearance: {
   254→                ...state.appearance,
   255→                language: settings.language ?? state.appearance.language,
   256→                accentColor: settings.accentColor ?? state.appearance.accentColor,
   257→              },
   258→            }));
   259→          }
   260→
   261→          if (profileRes.ok) {
   262→            const profile = await profileRes.json();
   263→            if (profile) {
   264→              const accessibility = profile.accessibility || {};
   265→              set((state) => ({
   266→                studentProfile: {
   267→                  ...state.studentProfile,
   268→                  name: profile.name ?? state.studentProfile.name,
   269→                  age: profile.age ?? state.studentProfile.age,
   270→                  schoolYear: profile.schoolYear ?? state.studentProfile.schoolYear,
   271→                  schoolLevel: profile.schoolLevel ?? state.studentProfile.schoolLevel,
   272→                  gradeLevel: profile.gradeLevel ?? state.studentProfile.gradeLevel,
   273→                  learningGoals: profile.learningGoals ?? state.studentProfile.learningGoals,
   274→                  // Character preferences
   275→                  preferredCoach: profile.preferredCoach ?? state.studentProfile.preferredCoach,
   276→                  preferredBuddy: profile.preferredBuddy ?? state.studentProfile.preferredBuddy,
   277→                  fontSize: accessibility.fontSize ?? state.studentProfile.fontSize,
   278→                  highContrast: accessibility.highContrast ?? state.studentProfile.highContrast,
   279→                  dyslexiaFont: accessibility.dyslexiaFont ?? state.studentProfile.dyslexiaFont,
   280→                  voiceEnabled: accessibility.voiceEnabled ?? state.studentProfile.voiceEnabled,
   281→                  simplifiedLanguage: accessibility.simplifiedLanguage ?? state.studentProfile.simplifiedLanguage,
   282→                  adhdMode: accessibility.adhdMode ?? state.studentProfile.adhdMode,
   283→                },
   284→              }));
   285→            }
   286→          }
   287→
   288→          set({ lastSyncedAt: new Date(), pendingSync: false });
   289→        } catch (error) {
   290→          logger.error('Settings load failed', { error: String(error) });
   291→        }
   292→      },
   293→    })
   294→);
