   719→// === CONVERSATION STORE ===
   720→
   721→interface ConversationState {
   722→  conversations: Conversation[];
   723→  currentConversationId: string | null;
   724→  // Sync state
   725→  lastSyncedAt: Date | null;
   726→  pendingSync: boolean;
   727→  // Actions
   728→  createConversation: (maestroId?: string) => Promise<string>;
   729→  addMessage: (conversationId: string, message: Omit<ChatMessage, 'id' | 'timestamp'>) => Promise<void>;
   730→  setCurrentConversation: (id: string | null) => void;
   731→  deleteConversation: (id: string) => Promise<void>;
   732→  clearConversations: () => void;
   733→  // Sync actions
   734→  syncToServer: () => Promise<void>;
   735→  loadFromServer: () => Promise<void>;
   736→}
   737→
   738→export const useConversationStore = create<ConversationState>()(
   739→  (set) => ({
   740→      conversations: [],
   741→      currentConversationId: null,
   742→      lastSyncedAt: null,
   743→      pendingSync: false,
   744→
   745→      createConversation: async (maestroId) => {
   746→        const tempId = crypto.randomUUID();
   747→        const conversation: Conversation = {
   748→          id: tempId,
   749→          title: 'New Conversation',
   750→          messages: [],
   751→          maestroId,
   752→          createdAt: new Date(),
   753→          updatedAt: new Date(),
   754→        };
   755→
   756→        // Optimistic update
   757→        set((state) => ({
   758→          conversations: [conversation, ...state.conversations],
   759→          currentConversationId: tempId,
   760→        }));
   761→
   762→        // Sync to server
   763→        try {
   764→          const response = await fetch('/api/conversations', {
   765→            method: 'POST',
   766→            headers: { 'Content-Type': 'application/json' },
   767→            body: JSON.stringify({ maestroId }),
   768→          });
   769→
   770→          if (response.ok) {
   771→            const serverConv = await response.json();
   772→            // Update with server ID
   773→            set((state) => ({
   774→              conversations: state.conversations.map((c) =>
   775→                c.id === tempId ? { ...c, id: serverConv.id } : c
   776→              ),
   777→              currentConversationId:
   778→                state.currentConversationId === tempId
   779→                  ? serverConv.id
   780→                  : state.currentConversationId,
   781→            }));
   782→            return serverConv.id;
   783→          }
   784→        } catch (error) {
   785→          logger.error('Failed to create conversation on server', { error: String(error) });
   786→        }
   787→
   788→        return tempId;
   789→      },
   790→
   791→      addMessage: async (conversationId, message) => {
   792→        const messageWithId = {
   793→          ...message,
   794→          id: crypto.randomUUID(),
   795→          timestamp: new Date(),
   796→        };
   797→
   798→        // Optimistic update
   799→        set((state) => ({
   800→          conversations: state.conversations.map((conv) =>
   801→            conv.id === conversationId
   802→              ? {
   803→                  ...conv,
   804→                  messages: [...conv.messages, messageWithId],
   805→                  updatedAt: new Date(),
   806→                  title:
   807→                    conv.messages.length === 0 && message.role === 'user'
   808→                      ? message.content.slice(0, 50)
   809→                      : conv.title,
   810→                }
   811→              : conv
   812→          ),
   813→          pendingSync: true,
   814→        }));
   815→
   816→        // Sync to server
   817→        try {
   818→          await fetch(`/api/conversations/${conversationId}/messages`, {
   819→            method: 'POST',
   820→            headers: { 'Content-Type': 'application/json' },
   821→            body: JSON.stringify({
   822→              role: message.role,
   823→              content: message.content,
   824→              toolCalls: (message as { toolCalls?: unknown }).toolCalls,
   825→            }),
   826→          });
   827→        } catch (error) {
   828→          logger.error('Failed to add message to server', { error: String(error) });
   829→        }
   830→      },
   831→
   832→      setCurrentConversation: (id) => set({ currentConversationId: id }),
   833→
   834→      deleteConversation: async (id) => {
   835→        // Optimistic update
   836→        set((state) => ({
   837→          conversations: state.conversations.filter((c) => c.id !== id),
   838→          currentConversationId:
   839→            state.currentConversationId === id
   840→              ? null
   841→              : state.currentConversationId,
   842→        }));
   843→
   844→        // Sync to server
   845→        try {
   846→          await fetch(`/api/conversations/${id}`, { method: 'DELETE' });
   847→        } catch (error) {
   848→          logger.error('Failed to delete conversation on server', { error: String(error) });
   849→        }
   850→      },
   851→
   852→      clearConversations: () =>
   853→        set({ conversations: [], currentConversationId: null }),
   854→
   855→      syncToServer: async () => {
   856→        // Conversations are synced immediately on each action
   857→        set({ lastSyncedAt: new Date(), pendingSync: false });
   858→      },
   859→
   860→      loadFromServer: async () => {
   861→        try {
   862→          const response = await fetch('/api/conversations?limit=50');
   863→          if (response.ok) {
   864→            const conversations = await response.json();
   865→            set({
   866→              conversations: conversations.map((c: {
   867→                id: string;
   868→                title: string;
   869→                maestroId: string;
   870→                createdAt: string;
   871→                updatedAt: string;
   872→                lastMessage?: string;
   873→              }) => ({
   874→                ...c,
   875→                messages: [], // Messages are loaded on-demand
   876→                createdAt: new Date(c.createdAt),
   877→                updatedAt: new Date(c.updatedAt),
   878→              })),
   879→              lastSyncedAt: new Date(),
   880→              pendingSync: false,
   881→            });
   882→          }
   883→        } catch (error) {
   884→          logger.error('Conversations load failed', { error: String(error) });
   885→        }
   886→      },
   887→    })
   888→);
