   915→export const useLearningsStore = create<LearningsState>()(
   916→  (set, get) => ({
   917→      learnings: [],
   918→      lastSyncedAt: null,
   919→
   920→      addLearning: async (learning) => {
   921→        try {
   922→          const response = await fetch('/api/learnings', {
   923→            method: 'POST',
   924→            headers: { 'Content-Type': 'application/json' },
   925→            body: JSON.stringify(learning),
   926→          });
   927→
   928→          if (response.ok) {
   929→            const serverLearning = await response.json();
   930→            set((state) => {
   931→              // Check if this was a reinforcement
   932→              if (serverLearning.reinforced) {
   933→                return {
   934→                  learnings: state.learnings.map((l) =>
   935→                    l.id === serverLearning.id
   936→                      ? { ...l, confidence: serverLearning.confidence, occurrences: serverLearning.occurrences }
   937→                      : l
   938→                  ),
   939→                };
   940→              }
   941→              // New learning
   942→              return {
   943→                learnings: [
   944→                  {
   945→                    ...serverLearning,
   946→                    createdAt: new Date(serverLearning.createdAt),
   947→                    updatedAt: new Date(serverLearning.updatedAt),
   948→                  },
   949→                  ...state.learnings,
   950→                ],
   951→              };
   952→            });
   953→          }
   954→        } catch (error) {
   955→          logger.error('Failed to add learning', { error: String(error) });
   956→        }
   957→      },
   958→
   959→      removeLearning: async (id) => {
   960→        set((state) => ({
   961→          learnings: state.learnings.filter((l) => l.id !== id),
   962→        }));
   963→
   964→        try {
   965→          await fetch(`/api/learnings?id=${id}`, { method: 'DELETE' });
   966→        } catch (error) {
   967→          logger.error('Failed to remove learning', { error: String(error) });
   968→        }
   969→      },
   970→
   971→      getLearningsByCategory: (category) => {
   972→        return get().learnings.filter((l) => l.category === category);
   973→      },
   974→
   975→      loadFromServer: async () => {
   976→        try {
   977→          const response = await fetch('/api/learnings');
   978→          if (response.ok) {
   979→            const learnings = await response.json();
   980→            set({
   981→              learnings: learnings.map((l: Learning & { createdAt: string; updatedAt: string }) => ({
   982→                ...l,
   983→                createdAt: new Date(l.createdAt),
   984→                updatedAt: new Date(l.updatedAt),
   985→              })),
   986→              lastSyncedAt: new Date(),
   987→            });
   988→          }
   989→        } catch (error) {
   990→          logger.error('Learnings load failed', { error: String(error) });
   991→        }
   992→      },
   993→    })
   994→);
