  1126→export const useCalendarStore = create<CalendarState>()(
  1127→  (set, get) => ({
  1128→      events: [],
  1129→
  1130→      addEvent: (event) =>
  1131→        set((state) => {
  1132→          const subjectLower = event.subject.toLowerCase();
  1133→          const maestroId = SUBJECT_TO_MAESTRO[subjectLower];
  1134→          return {
  1135→            events: [
  1136→              ...state.events,
  1137→              {
  1138→                ...event,
  1139→                id: crypto.randomUUID(),
  1140→                completed: false,
  1141→                maestroSuggested: maestroId,
  1142→              },
  1143→            ],
  1144→          };
  1145→        }),
  1146→
  1147→      updateEvent: (id, updates) =>
  1148→        set((state) => ({
  1149→          events: state.events.map((e) =>
  1150→            e.id === id ? { ...e, ...updates } : e
  1151→          ),
  1152→        })),
  1153→
  1154→      deleteEvent: (id) =>
  1155→        set((state) => ({
  1156→          events: state.events.filter((e) => e.id !== id),
  1157→        })),
  1158→
  1159→      toggleCompleted: (id) =>
  1160→        set((state) => ({
  1161→          events: state.events.map((e) =>
  1162→            e.id === id ? { ...e, completed: !e.completed } : e
  1163→          ),
  1164→        })),
  1165→
  1166→      getUpcomingEvents: (days) => {
  1167→        const now = new Date();
  1168→        const future = new Date(now.getTime() + days * 24 * 60 * 60 * 1000);
  1169→        return get()
  1170→          .events.filter(
  1171→            (e) => !e.completed && new Date(e.date) >= now && new Date(e.date) <= future
  1172→          )
  1173→          .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  1174→      },
  1175→
  1176→      getEventsBySubject: (subject) => {
  1177→        return get().events.filter(
  1178→          (e) => e.subject.toLowerCase() === subject.toLowerCase()
  1179→        );
  1180→      },
  1181→
  1182→      getSuggestedMaestri: () => {
  1183→        const upcoming = get().getUpcomingEvents(7);
  1184→        const suggestions: Map<string, { count: number; nearestDays: number; types: Set<string> }> = new Map();
  1185→
  1186→        const now = new Date();
  1187→        upcoming.forEach((event) => {
  1188→          const maestroId = event.maestroSuggested;
  1189→          if (!maestroId) return;
  1190→
  1191→          const daysUntil = Math.ceil(
  1192→            (new Date(event.date).getTime() - now.getTime()) / (24 * 60 * 60 * 1000)
  1193→          );
  1194→
  1195→          if (suggestions.has(maestroId)) {
  1196→            const existing = suggestions.get(maestroId)!;
  1197→            existing.count++;
  1198→            existing.nearestDays = Math.min(existing.nearestDays, daysUntil);
  1199→            existing.types.add(event.type);
  1200→          } else {
  1201→            suggestions.set(maestroId, {
  1202→              count: 1,
  1203→              nearestDays: daysUntil,
  1204→              types: new Set([event.type]),
  1205→            });
  1206→          }
  1207→        });
  1208→
  1209→        return Array.from(suggestions.entries())
  1210→          .map(([maestroId, data]) => {
  1211→            let priority: 'high' | 'medium' | 'low' = 'low';
  1212→            let reason = '';
  1213→
  1214→            if (data.nearestDays <= 1) {
  1215→              priority = 'high';
  1216→              reason = data.types.has('exam') || data.types.has('test')
  1217→                ? 'Test tomorrow - review now!'
  1218→                : 'Event tomorrow';
  1219→            } else if (data.nearestDays <= 3) {
  1220→              priority = 'high';
  1221→              reason = `${data.count} event${data.count > 1 ? 's' : ''} in ${data.nearestDays} days`;
  1222→            } else if (data.nearestDays <= 5) {
  1223→              priority = 'medium';
  1224→              reason = `Prepare for upcoming ${Array.from(data.types).join('/')}`;
  1225→            } else {
  1226→              priority = 'low';
  1227→              reason = `${data.count} event${data.count > 1 ? 's' : ''} this week`;
  1228→            }
  1229→
  1230→            return { maestroId, reason, priority };
  1231→          })
  1232→          .sort((a, b) => {
  1233→            const priorityOrder = { high: 0, medium: 1, low: 2 };
  1234→            return priorityOrder[a.priority] - priorityOrder[b.priority];
  1235→          });
  1236→      },
  1237→    })
  1238→);
  1239→
  1240→// === UI STORE ===
  1241→
  1242→interface UIState {
  1243→  sidebarOpen: boolean;
  1244→  settingsOpen: boolean;
  1245→  currentView: 'maestri' | 'chat' | 'voice' | 'quiz' | 'flashcards' | 'homework' | 'progress';
  1246→  // Focus Mode - fullscreen tool view
  1247→  focusMode: boolean;
  1248→  focusTool: ToolState | null;
  1249→  focusToolType: ToolType | null;
  1250→  focusMaestroId: string | null;
  1251→  focusInteractionMode: 'voice' | 'chat';
  1252→  // Actions
  1253→  toggleSidebar: () => void;
  1254→  setSidebarOpen: (open: boolean) => void;
  1255→  toggleSettings: () => void;
  1256→  setCurrentView: (view: UIState['currentView']) => void;
  1257→  // Focus Mode Actions
  1258→  enterFocusMode: (toolType: ToolType, maestroId?: string, interactionMode?: 'voice' | 'chat') => void;
  1259→  setFocusTool: (tool: ToolState | null) => void;
  1260→  exitFocusMode: () => void;
  1261→}
  1262→
  1263→export const useUIStore = create<UIState>((set) => ({
  1264→  sidebarOpen: true,
  1265→  settingsOpen: false,
  1266→  currentView: 'maestri',
  1267→  focusMode: false,
  1268→  focusTool: null,
  1269→  focusToolType: null,
  1270→  focusMaestroId: null,
  1271→  focusInteractionMode: 'chat',
  1272→  toggleSidebar: () => set((state) => ({ sidebarOpen: !state.sidebarOpen })),
  1273→  setSidebarOpen: (sidebarOpen) => set({ sidebarOpen }),
  1274→  toggleSettings: () => set((state) => ({ settingsOpen: !state.settingsOpen })),
  1275→  setCurrentView: (currentView) => set({ currentView }),
  1276→  enterFocusMode: (toolType, maestroId, interactionMode = 'chat') => set({
  1277→    focusMode: true,
  1278→    focusToolType: toolType,
  1279→    focusMaestroId: maestroId || null,
  1280→    focusInteractionMode: interactionMode,
  1281→    focusTool: null, // Will be set when tool is created
  1282→  }),
  1283→  setFocusTool: (tool) => set({ focusTool: tool }),
  1284→  exitFocusMode: () => set({
  1285→    focusMode: false,
  1286→    focusTool: null,
  1287→    focusToolType: null,
  1288→    focusMaestroId: null,
  1289→    focusInteractionMode: 'chat',
  1290→  }),
  1291→}));
  1292→
  1293→// === SYNC HOOK ===
  1294→
  1295→export async function initializeStores() {
  1296→  // Ensure user exists (creates cookie if needed)
  1297→  await fetch('/api/user');
  1298→
  1299→  // Load data from server
  1300→  await Promise.all([
  1301→    useSettingsStore.getState().loadFromServer(),
  1302→    useProgressStore.getState().loadFromServer(),
  1303→    useConversationStore.getState().loadFromServer(),
  1304→    useLearningsStore.getState().loadFromServer(),
  1305→  ]);
  1306→}
  1307→
  1308→export function setupAutoSync(intervalMs = 30000) {
  1309→  // Auto-sync every 30 seconds if there are pending changes
  1310→  return setInterval(async () => {
  1311→    const settings = useSettingsStore.getState();
  1312→    const progress = useProgressStore.getState();
  1313→
  1314→    if (settings.pendingSync) {
  1315→      await settings.syncToServer();
  1316→    }
  1317→    if (progress.pendingSync) {
  1318→      await progress.syncToServer();
  1319→    }
  1320→  }, intervalMs);
  1321→}
